module RefModule(datain, dataout, clk, clr, WE);input [31:0] datain;
    output [31:0] dataout;
    input clk, clr, WE;

    reg [31:0] obf_register;

always @(posedge clk or posedge clr)
begin
  if(clr)
    obf_register = 0;  
  else
    if(WE == 1)
    obf_register =  datain;
end    
  assign dataout = obf_register;

endmodule
